#include <iostream>
#include <vector>
#include <unordered_set>

using namespace std;

int main() {
    int n;
    cin >> n;
    vector<int> nums(n);
    for (int i = 0; i < n; ++i) {
        cin >> nums[i];
    }

    unordered_set<int> numSet(nums.begin(), nums.end());
    int count = 0;

    for (int i = 0; i < n; ++i) {
        bool found = false;
        for (int j = 0; j < n; ++j) {
            if (j == i) continue; // 跳过自身
            int target = nums[i] - nums[j];
            if (numSet.count(target) && target != nums[j]) {
                found = true;
                break;
            }
        }
        if (found) {
            count++;
        }
    }

    cout << count << endl;

    return 0;
}
